PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "robotics_kits" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" text, "brand" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "groups" ("id" integer primary key autoincrement not null, "name" varchar not null, "level" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "username" varchar not null, "email" varchar not null, "password" varchar not null, "role" varchar check ("role" in ('student', 'teacher', 'administrative')) not null, "group_id" integer, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, foreign key("group_id") references "groups"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "courses" ("id" integer primary key autoincrement not null, "course_key" varchar not null, "title" varchar not null, "cover" varchar, "content" text, "didactic_material" text, "kit_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("kit_id") references "robotics_kits"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "course_group" ("id" integer primary key autoincrement not null, "course_id" integer not null, "group_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("course_id") references "courses"("id") on delete cascade, foreign key("group_id") references "groups"("id") on delete cascade);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE UNIQUE INDEX "courses_course_key_unique" on "courses" ("course_key");
COMMIT;
